INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('trinity', 'Trinity', 1945, 'USA', 'Alamogordo, New Mexico', 33.677, -106.475, 1, 21, 'First ever atomic bomb test — plutonium implosion device (Gadget)', 'The world''s first nuclear explosion. The test validated the implosion design used in the Fat Man bomb dropped on Nagasaki. The blast was visible from three states. The crater is still radioactive.', 'trinity');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('crossroads', 'Operation Crossroads', 1946, 'USA', 'Bikini Atoll, Marshall Islands', 11.6, 165.5, 2, 23, 'Effects of nuclear weapons on naval vessels — Able (airburst) and Baker (underwater)', 'Two tests against a fleet of 95 target ships. Baker was the first underwater nuclear explosion, producing a massive radioactive lagoon that contaminated the entire target fleet. The tests displaced the Bikini Islanders permanently.', 'crossroads');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('sandstone', 'Operation Sandstone', 1948, 'USA', 'Enewetak Atoll, Pacific Proving Grounds', 11.5, 162.2, 3, 49, 'Weapon design improvements — tested new fission bomb cores', 'Three tests (X-Ray, Yoke, Zebra) focused on improving atomic bomb efficiency. Introduced the levitated pit design that significantly boosted yield-to-weight ratio. Multiple DoE films cover this operation from Navy, Air Force, and Army perspectives.', 'sandstone');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('ranger', 'Operation Ranger', 1951, 'USA', 'Nevada Test Site', 37.1, -116, 5, 22, 'First tests at the Nevada Test Site — rapid development of smaller, lighter weapons', 'Five tests in January-February 1951. The first nuclear tests conducted on the U.S. mainland since Trinity. Included the first test of the Mark 6 bomb design.', 'ranger');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('greenhouse', 'Operation Greenhouse', 1951, 'USA', 'Enewetak Atoll, Pacific Proving Grounds', 11.5, 162.2, 4, 225, 'Thermonuclear weapon component tests — first boosted fission devices', 'Four tests (Dog, Easy, George, Item). George tested the first thermonuclear fusion boosting — a crucial step toward the H-bomb. Item was the first boosted fission weapon. The 225 kt yield was double what was predicted.', 'greenhouse');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('buster-jangle', 'Operation Buster-Jangle', 1951, 'USA', 'Nevada Test Site', 37.1, -116, 7, 31, 'Weapon effects tests — troops maneuvered near ground zero', 'Seven tests including troop maneuvers (Exercise Desert Rock I and II). Troops were positioned as close as 7 miles from ground zero. Also tested nuclear warheads for anti-aircraft missiles.', 'buster-jangle');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('tumbler-snapper', 'Operation Tumbler-Snapper', 1952, 'USA', 'Nevada Test Site', 37.1, -116, 8, 31, 'Airdrop testing and weapon effects on structures', 'Eight tests. First series to test actual airdropped weapons. Included civil defense effects tests with houses, mannequins, and military equipment placed at known distances from ground zero.', 'tumbler-snapper');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('ivy', 'Operation Ivy', 1952, 'USA', 'Enewetak Atoll, Pacific Proving Grounds', 11.5, 162.2, 2, 10400, 'First full-scale thermonuclear test (H-bomb) — Mike shot', 'Two tests: Mike (10.4 Mt) and King (500 kt). Mike was the world''s first hydrogen bomb — a cryogenic device weighing 82 tons that vaporized the island of Elugelab. King was the largest pure fission bomb ever tested. The Mike shot was kept secret from the American public for years. Yield: 694 Hiroshimas.', 'ivy');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('upshot-knothole', 'Operation Upshot-Knothole', 1953, 'USA', 'Nevada Test Site', 37.1, -116, 11, 61, 'Weapon development and civil defense effects', 'Eleven tests. Included the first test of a nuclear artillery shell (the M65 280mm Atomic Cannon). The ''Dirty Harry'' and ''Harry'' tests caused significant off-site fallout that reached St. George, Utah.', 'upshot-knothole');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('castle', 'Operation Castle', 1954, 'USA', 'Bikini Atoll & Enewetak Atoll', 11.6, 165.5, 6, 15000, 'Deployable thermonuclear weapons — dry fuel H-bombs', 'Six tests. Bravo (15 Mt) was the largest nuclear test ever conducted by the United States — 2.5x the expected yield. The error caused catastrophic radiological contamination: a Japanese fishing boat (Daigo Fukuryu Maru) was irradiated, crew members died, and widespread fallout rained on inhabited atolls. The Bravo shot yielded 1,000 Hiroshimas.', 'castle');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('teapot', 'Operation Teapot', 1955, 'USA', 'Nevada Test Site', 37.1, -116, 14, 43, 'Weapon effects and civil defense — ''Operation Cue'' mock suburb nuked', 'Fourteen tests including the famous ''Operation Cue'' civil defense test: a full mock suburban neighborhood built with houses, mannequins, food, and cars was placed at varying distances from the blast and nuked. Also tested nuclear warheads for air defense missiles.', 'teapot');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('wigwam', 'Operation Wigwam', 1955, 'USA', 'Pacific Ocean (off California coast)', 28.7, -126.3, 1, 30, 'Deep underwater nuclear test — anti-submarine warfare effects', 'A single 30 kt test conducted 2,000 feet underwater, 500 miles off the California coast. Tested the effects of deep underwater nuclear explosions on naval vessels and submarines. The spray dome was over a mile wide.', 'wigwam');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('redwing', 'Operation Redwing', 1956, 'USA', 'Enewetak Atoll & Bikini Atoll', 11.5, 162.2, 17, 5000, 'Advanced thermonuclear weapon development — including first airborne H-bomb drop', 'Seventeen tests. Included the first air-dropped thermonuclear bomb (Cherokee, 3.8 Mt). Also tested the Lacrosse, the first surface-to-surface missile nuclear warhead. Massive series covering the full range of U.S. nuclear capabilities.', 'redwing');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('hardtack', 'Operation Hardtack', 1958, 'USA', 'Pacific Proving Grounds & Johnston Atoll', 11.5, 162.2, 35, 9300, 'Largest test series — full spectrum of weapons development', 'Thirty-five tests, the largest single U.S. test series. Two phases: Hardtack I in the Pacific (weapons development, including 9.3 Mt Poplar shot) and Hardtack II in Nevada (weapon effects, safety tests). Included high-altitude tests that caused unexpected electromagnetic pulse effects.', 'hardtack');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('argus', 'Operation Argus', 1958, 'USA', 'South Atlantic Ocean', -49.5, -7.5, 3, 1.7, 'High-altitude nuclear tests — electromagnetic pulse and radiation belt effects', 'Three secret high-altitude tests conducted in the South Atlantic. Each warhead was launched by rocket and detonated at 100+ miles altitude. Created artificial radiation belts. Kept classified for years. The tests validated theories about EMP that would later affect weapons design.', 'argus');
INSERT INTO operations (id, name, year, country, location_name, latitude, longitude, total_tests, max_yield_kt, purpose, description, slug) VALUES ('dominic', 'Operation Dominic', 1962, 'USA', 'Christmas Island & Johnston Island & Pacific Ocean', 1.9, -157.4, 36, 8300, 'Last atmospheric test series — response to Soviet resumption of testing', 'Thirty-six tests in 1962. The largest atmospheric test series since Hardtack. Included the Starfish Prime high-altitude test (1.4 Mt at 400 km altitude) which created an artificial aurora visible from Hawaii and knocked out streetlights on Oahu. The last atmospheric nuclear test was conducted on November 4, 1962. Eight months later, the Limited Test Ban Treaty banned atmospheric testing forever.', 'dominic');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('trinity-shot', 'trinity', 'Nuclear Test Film - Trinity Shot', 'gov.doe.0800001', 'https://archive.org/details/gov.doe.0800001', 21, 'Trinity', '1945-07-16', 'Alamogordo, New Mexico', 'Department of Energy', 17560, 'The world''s first nuclear explosion. At 5:29 a.m. on 16 July 1945, the plutonium implosion device known as the Gadget detonated atop a 100-foot steel tower in the Jornada del Muerto desert of New Mexico, releasing about 21 kilotons. The flash was seen in three states; the shock wave broke windows 120 miles away. The test validated the implosion design used three weeks later over Nagasaki.', 'The tower was vaporized and the desert sand fused into a mildly radioactive blue-green glass later named trinitite. Fallout drifted across ranching country to the north and east; families living downwind — the Tularosa Basin downwinders — were never warned, never evacuated, and to this day are excluded from federal radiation-compensation programs. The crater remains slightly radioactive and is opened to the public twice a year.', 'Gadget — plutonium implosion device', 'https://archive.org/services/img/gov.doe.0800001', 'trinity-shot');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('crossroads-able', 'crossroads', 'Nuclear Test Film - Operation Crossroads', 'gov.doe.0800002', 'https://archive.org/details/gov.doe.0800002', 23, 'Able / Baker', '1946-07-01', 'Bikini Atoll', 'Department of Energy', 15000, 'Operation Crossroads put a fleet of 95 surplus and captured warships in Bikini lagoon and detonated atomic bombs against them to study effects on naval vessels. Able was an airburst on 1 July 1946; Baker, on 25 July, was detonated 90 feet underwater — the first underwater nuclear explosion. Baker threw a hollow column of two million tons of water a mile into the sky and dropped a radioactive mist back onto the fleet.', 'Baker contaminated all 95 target ships so thoroughly that decontamination failed; most were scuttled, including the carrier USS Saratoga and the battleship USS Arkansas. It was, in the words of the cleanup commander, ''the world''s first nuclear disaster.'' The 167 Bikini Islanders, told their evacuation would be temporary and ''for the good of mankind,'' have never been able to return permanently.', 'Mk-3A Fat Man-type fission bombs', 'https://archive.org/services/img/gov.doe.0800002', 'crossroads-able');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('sandstone-general', 'sandstone', 'Nuclear Test Film - Operation Sandstone', 'gov.doe.0800003', 'https://archive.org/details/gov.doe.0800003', 49, 'X-Ray / Yoke / Zebra', '1948-04-15', 'Enewetak Atoll', 'Department of Energy', 48549, 'Operation Sandstone (1948, Enewetak Atoll) was a weapons-laboratory series rather than a military exercise — three shots, X-Ray, Yoke and Zebra, that proved the levitated-pit design and roughly doubled the yield-to-weight efficiency of the American arsenal. The results let the U.S. build far more weapons from the same scarce fissile material.', 'The Enewetak people had already been displaced in 1947 and moved to Ujelang, a smaller, poorer atoll. Sandstone''s efficiency gains accelerated the arms race; the design principles it confirmed underpinned every fission weapon that followed.', 'Levitated-pit fission cores (X-Ray, Yoke, Zebra)', 'https://archive.org/services/img/gov.doe.0800003', 'sandstone-general');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('sandstone-navy', 'sandstone', 'Nuclear Test Film - Operation Sandstone - Navy', 'gov.doe.0800008', 'https://archive.org/details/gov.doe.0800008', 49, 'Navy perspective', '1948', 'Enewetak Atoll', 'Department of Energy', 51514, 'The U.S. Navy''s documentary record of Operation Sandstone (1948), covering the fleet support, instrumentation ships and diagnostic photography for the X-Ray, Yoke and Zebra shots at Enewetak.', 'One of several service-specific films of the same series — the military filmed these tests exhaustively from every institutional perspective. The Enewetak islanders remained in exile on Ujelang throughout.', 'Levitated-pit fission cores', 'https://archive.org/services/img/gov.doe.0800008', 'sandstone-navy');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('sandstone-usaf', 'sandstone', 'Nuclear Test Film - Operation Sandstone - U.S. Air Force', 'gov.doe.0800005', 'https://archive.org/details/gov.doe.0800005', 49, 'USAF perspective', '1948', 'Enewetak Atoll', 'Department of Energy', 49278, 'The U.S. Air Force''s documentary record of Operation Sandstone (1948) — airborne sampling of the mushroom clouds, cloud tracking, and aerial cinematography of the X-Ray, Yoke and Zebra detonations at Enewetak Atoll.', 'Air Force ''cloud sampling'' pilots flew directly through the radioactive clouds to collect debris for analysis, an early and poorly understood occupational exposure that recurred across the entire test program.', 'Levitated-pit fission cores', 'https://archive.org/services/img/gov.doe.0800005', 'sandstone-usaf');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('sandstone-army', 'sandstone', 'Nuclear Test Film - Operation Sandstone - U.S. Army Engineers', 'gov.doe.0800006', 'https://archive.org/details/gov.doe.0800006', 49, 'Army Engineers perspective', '1948', 'Enewetak Atoll', 'Department of Energy', 47159, 'The U.S. Army Engineers'' record of Operation Sandstone (1948) — the construction of test towers, instrument bunkers and camp facilities across Enewetak Atoll that made the three-shot series possible.', 'The engineering footprint left on Enewetak grew with every Pacific series; by the 1970s cleanup, contaminated debris from decades of testing was sealed under the Runit Dome, a concrete cap that is now cracking and leaking as sea levels rise.', 'Levitated-pit fission cores', 'https://archive.org/services/img/gov.doe.0800006', 'sandstone-army');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('sandstone-blast', 'sandstone', 'Nuclear Test Film - Operation Sandstone - Blast Measurement', 'gov.doe.0800007', 'https://archive.org/details/gov.doe.0800007', 49, 'Blast measurement', '1948', 'Enewetak Atoll', 'Department of Energy', 41653, 'The blast-measurement record of Operation Sandstone (1948): the gauge lines, pressure instruments and high-speed photography used to quantify the overpressure and thermal output of the X-Ray, Yoke and Zebra shots.', 'Blast and thermal data gathered here fed directly into the weapons-effects manuals that would later be used to plan civil-defense tests against mock American towns.', 'Levitated-pit fission cores', 'https://archive.org/services/img/gov.doe.0800007', 'sandstone-blast');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('sandstone-ecg', 'sandstone', 'Nuclear Test Film - Operation Sandstone - EC and G', 'gov.doe.0800004', 'https://archive.org/details/gov.doe.0800004', 49, 'EC&G instrumentation', '1948', 'Enewetak Atoll', 'Department of Energy', 33031, 'The EG&G instrumentation record of Operation Sandstone (1948). Edgerton, Germeshausen & Grier — the firm behind the high-speed Rapatronic cameras — documented the first microseconds of each fireball at Enewetak.', 'EG&G''s Rapatronic photography, capturing exposures of ten-millionths of a second, produced the iconic images of fireballs still milliseconds old — the ''rope tricks'' of vaporizing tower guy-wires that became the visual signature of the atomic age.', 'Levitated-pit fission cores', 'https://archive.org/services/img/gov.doe.0800004', 'sandstone-ecg');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('ranger-buster', 'ranger', 'Nuclear Test Film - Operation Ranger, Operation Buster/Jangle', 'gov.doe.0800010', 'https://archive.org/details/gov.doe.0800010', 31, 'Ranger + Buster/Jangle compilation', '1951', 'Nevada Test Site', 'Department of Energy', 57198, 'A combined record of Operation Ranger (January–February 1951) and Operation Buster-Jangle (October–November 1951), the first tests on the U.S. mainland since Trinity. Ranger opened the Nevada Test Site with five air-dropped shots; Buster-Jangle added the first underground and surface cratering tests and the Desert Rock exercises that marched troops toward ground zero.', 'Under Exercise Desert Rock, soldiers were positioned in trenches as close as seven miles from detonations and then advanced toward the still-rising cloud to study the psychological and physical effects on troops. Many of these ''atomic veterans'' developed cancers; their exposure records were classified for decades.', 'Air-dropped fission bombs; Desert Rock troop exercises', 'https://archive.org/services/img/gov.doe.0800010', 'ranger-buster');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('greenhouse', 'greenhouse', 'Nuclear Test Film - Operation Greenhouse', 'gov.doe.0800009', 'https://archive.org/details/gov.doe.0800009', 225, 'Dog / Easy / George / Item', '1951-04-08', 'Enewetak Atoll', 'Department of Energy', 56359, 'Operation Greenhouse (1951, Enewetak) tested the physics that made the hydrogen bomb possible. The George shot used a fission bomb to ignite a small quantity of fusion fuel — the first time a thermonuclear reaction was achieved on Earth. The Item shot was the first boosted-fission weapon. The 225-kiloton series was twice as powerful as predicted.', 'George proved Edward Teller and Stanislaw Ulam''s ideas were sound and cleared the path to Ivy Mike eighteen months later. The Enewetak islanders, still exiled on Ujelang, watched their home become the proving ground for the thermonuclear age.', 'George (thermonuclear principle) and Item (boosted fission)', 'https://archive.org/services/img/gov.doe.0800009', 'greenhouse');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('tumbler-snapper', 'tumbler-snapper', 'Nuclear Test Film - Operation Tumbler-Snapper', 'gov.doe.0800011', 'https://archive.org/details/gov.doe.0800011', 31, 'Tumbler-Snapper series', '1952-04-01', 'Nevada Test Site', 'Department of Energy', 51454, 'Operation Tumbler-Snapper (1952, Nevada) ran eight shots split between weapons development (''Tumbler'') and military effects (''Snapper''). It produced some of the most-reproduced footage of the era, including high-speed film of the shock front racing across the desert floor and the structures, vehicles and mannequins arranged to absorb it.', 'Fallout from the Nevada series drifted across Utah and into the Midwest. The Atomic Energy Commission''s public assurances of safety stood in sharp contrast to the radiation monitoring it was quietly conducting on the same downwind communities.', 'Air-dropped and tower-mounted fission devices', 'https://archive.org/services/img/gov.doe.0800011', 'tumbler-snapper');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('ivy-mike', 'ivy', 'Nuclear Test Film - Operation Ivy', 'gov.doe.0800012', 'https://archive.org/details/gov.doe.0800012', 10400, 'Mike', '1952-11-01', 'Enewetak Atoll', 'Department of Energy', 61930, 'On 1 November 1952 the United States detonated the first true hydrogen bomb. Mike was not a deliverable weapon but an 82-ton experimental apparatus, a building-sized cryogenic flask of liquid deuterium chilled near absolute zero. It yielded 10.4 megatons — roughly 700 Hiroshimas — and completely vaporized the island of Elugelab, leaving a crater 1.2 miles wide and 160 feet deep where land had been.', 'The fireball was over three miles across. Irradiated coral fell on ships 30 miles away, and the mushroom cloud spread 100 miles. The film was kept from the American public for years; a sanitized version was released only after the Soviet Union tested its own thermonuclear device. Mike proved that weapons of effectively unlimited yield were now possible.', 'Mike — cryogenic liquid-deuterium "Sausage" device', 'https://archive.org/services/img/gov.doe.0800012', 'ivy-mike');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('upshot-knothole', 'upshot-knothole', 'Nuclear Test Film - Operation Upshot-Knothole', 'gov.doe.0800015', 'https://archive.org/details/gov.doe.0800015', 61, 'Upshot-Knothole series', '1953-03-17', 'Nevada Test Site', 'Department of Energy', 41065, 'Operation Upshot-Knothole (1953, Nevada) ran eleven shots, among them Grable — a 15-kiloton shell fired from the M65 280mm ''Atomic Cannon,'' the only nuclear artillery round ever detonated in flight by the U.S. The series paired weapons development with elaborate civil-effects experiments.', 'The Harry shot of 19 May 1953 — later nicknamed ''Dirty Harry'' — blanketed St. George, Utah with fallout so heavy that motorists were stopped and their cars washed down. The downwind cancer toll from this and adjacent shots became one of the central grievances behind the later Radiation Exposure Compensation Act.', 'Fission devices including the Grable nuclear artillery shell', 'https://archive.org/services/img/gov.doe.0800015', 'upshot-knothole');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('upshot-knothole-52', 'upshot-knothole', 'Nuclear Test Film - Operation Upshot-Knothole, 5.2', 'gov.doe.0800016', 'https://archive.org/details/gov.doe.0800016', 61, 'Upshot-Knothole 5.2', '1953', 'Nevada Test Site', 'Department of Energy', 29506, 'A second reel of Operation Upshot-Knothole (1953) concentrating on the weapons-effects program: the test houses, automobiles, bomb shelters and instrument arrays built across the Nevada desert and exposed to the blasts.', 'Footage of frame houses bursting into flame and collapsing under the shock front became the template for the civil-defense films that told Americans they could survive a nuclear war by ducking under furniture.', 'Fission devices; civil-effects test structures', 'https://archive.org/services/img/gov.doe.0800016', 'upshot-knothole-52');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('castle', 'castle', 'Nuclear Test Film - Operation Castle', 'gov.doe.0800013', 'https://archive.org/details/gov.doe.0800013', 15000, 'Bravo / Romeo / Koon / Union / Yankee / Nectar', '1954-03-01', 'Bikini Atoll', 'Department of Energy', 57972, 'Operation Castle (1954, Bikini) fielded the first deliverable thermonuclear weapons using solid, ''dry'' lithium-deuteride fuel. Its opening shot, Bravo, on 1 March 1954, yielded 15 megatons — two and a half times the predicted yield and the largest device the United States ever detonated, about 1,000 Hiroshimas.', 'Bravo became the worst radiological disaster in American history. A miscalculated yield and an unexpected wind shift dumped heavy fallout across the inhabited atolls of Rongelap and Utirik, whose people suffered acute radiation sickness, lasting illness and exile. The Japanese tuna boat Daigo Fukuryu Maru (Lucky Dragon No. 5), 80 miles away, was coated in radioactive ash; its entire crew fell ill and radio operator Aikichi Kuboyama died, triggering an international crisis and the global anti-nuclear movement.', 'Shrimp — solid lithium-deuteride dry-fuel device', 'https://archive.org/services/img/gov.doe.0800013', 'castle');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('teapot', 'teapot', 'Nuclear Test Film - Operation Teapot', 'gov.doe.0800017', 'https://archive.org/details/gov.doe.0800017', 43, 'Teapot series', '1955-02-18', 'Nevada Test Site', 'Department of Energy', 53978, 'Operation Teapot (1955, Nevada) ran fourteen shots developing smaller tactical warheads and air-defense weapons. It is best remembered for its civil-effects program, which built and destroyed entire furnished structures to study how American homes and families would fare under atomic attack.', 'Teapot''s effects data was packaged for the public as reassurance. The same blasts that flattened the test houses were sending measurable fallout across the country, a contradiction the Atomic Energy Commission managed through secrecy rather than warning.', 'Tactical and air-defense fission devices', 'https://archive.org/services/img/gov.doe.0800017', 'teapot');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('operation-cue', 'teapot', 'Atomic Bomb Test - Operation Cue', 'CEP_00_071', 'https://archive.org/details/CEP_00_071', 29, 'Operation Cue (civil defense mock suburb)', '1955-05-05', 'Nevada Test Site', 'Federal Civil Defense Administration', 261776, 'On 5 May 1955, under the Teapot series, the Federal Civil Defense Administration built ''Survival Town'' — a complete mock American suburb of furnished houses, stocked supermarkets, parked cars, electrical lines and clothed mannequin families — and detonated a 29-kiloton bomb beside it. Operation Cue filmed the destruction as civil-defense instruction.', 'The footage of mannequin families incinerated and houses blown to splinters was meant to teach survival, but it documented the opposite: at close range nothing survived. With over a quarter-million views, it remains one of the most-watched and most chilling artifacts of Cold War civil defense.', 'Apple-2 shot, 29 kt tower device', 'https://archive.org/services/img/CEP_00_071', 'operation-cue');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('wigwam', 'wigwam', 'Nuclear Test Film - Operation Wigwam', 'gov.doe.0800018', 'https://archive.org/details/gov.doe.0800018', 30, 'Wigwam', '1955-05-14', 'Pacific Ocean', 'Department of Energy', 61346, 'Operation Wigwam (14 May 1955) was a single 30-kiloton shot detonated 2,000 feet underwater, 500 miles off the California coast — the only deep-water nuclear test ever conducted by the United States. It studied the effects of a nuclear depth charge on submarines, three of which were tethered at distance as scale-model targets.', 'Wigwam''s spray dome rose over a mile wide. Crews aboard the support ships were exposed to contaminated water, and like the atomic veterans of the desert tests, spent decades fighting for recognition of their illnesses.', 'Mk-90 Betty deep-water nuclear depth charge', 'https://archive.org/services/img/gov.doe.0800018', 'wigwam');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('redwing', 'redwing', 'Nuclear Test Film - Operation Redwing', 'gov.doe.0800019', 'https://archive.org/details/gov.doe.0800019', 5000, 'Redwing series', '1956-05-04', 'Enewetak Atoll', 'Department of Energy', 61855, 'Operation Redwing (1956, Bikini and Enewetak) ran seventeen shots to develop a second generation of thermonuclear weapons. Its Cherokee shot was the first U.S. airdrop of a hydrogen bomb, a 3.8-megaton burst over Bikini — proof that the megaton-range weapon was now a deployable bomb rather than a laboratory experiment.', 'Redwing returned to atolls already heavily contaminated by Castle Bravo two years earlier, adding to a fallout burden the Marshallese still live with. The series confirmed the U.S. could deliver multi-megaton weapons by aircraft anywhere on Earth.', 'Thermonuclear devices incl. Cherokey air-drop', 'https://archive.org/services/img/gov.doe.0800019', 'redwing');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('nuclear-testing-review', NULL, 'Nuclear Test Film - Nuclear Testing Review', 'gov.doe.0800000', 'https://archive.org/details/gov.doe.0800000', NULL, 'Overview film', NULL, 'Various', 'Department of Energy', 47488, 'A Department of Energy overview film summarizing the U.S. atmospheric testing program — a compilation that stitches together footage from numerous operations into a single official narrative of the nuclear age.', 'Films like this were the public face of a program whose true scale, fallout and human cost remained classified for decades. What they show is real; what they leave out is most of the story.', 'Compilation', 'https://archive.org/services/img/gov.doe.0800000', 'nuclear-testing-review');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('atomic-bomb-blast-effects', NULL, 'Atomic Bomb Blast Effects', '0707_Atomic_Bomb_Blast_Effects', 'https://archive.org/details/0707_Atomic_Bomb_Blast_Effects', NULL, 'Compilation', NULL, 'Various', 'U.S. Army', 67671, 'A U.S. Army compilation documenting the physical effects of atomic blasts — overpressure, thermal radiation and shock — on structures, vehicles and test materials across multiple Nevada shots.', 'Assembled as training material, the film distills years of weapons-effects testing into a catalogue of destruction, the same data that shaped both military targeting and civil-defense doctrine.', 'Compilation', 'https://archive.org/services/img/0707_Atomic_Bomb_Blast_Effects', 'atomic-bomb-blast-effects');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('starfish-prime', 'dominic', 'Starfish Prime Interim Report By Commander JTF-8', 'StarfishPrimeInterimReportByCommanderJTF8', 'https://archive.org/details/StarfishPrimeInterimReportByCommanderJTF8', 1400, 'Starfish Prime', '1962-07-09', 'Johnston Island', 'Department of Energy', 21262, 'Part of Operation Dominic, Starfish Prime was a 1.4-megaton warhead detonated on 9 July 1962 at an altitude of 250 miles above Johnston Island — a deliberate high-altitude nuclear test. It lit an artificial aurora seen across the Pacific and produced an electromagnetic pulse that reached Hawaii.', 'The EMP knocked out streetlights, tripped burglar alarms and damaged telephone equipment 900 miles away in Honolulu. The blast pumped the Earth''s magnetic field with charged particles, creating artificial radiation belts that crippled or destroyed at least six satellites over the following months — the first demonstration that a nuclear weapon in space could disable the technology below.', 'W49 thermonuclear warhead on a Thor rocket', 'https://archive.org/services/img/StarfishPrimeInterimReportByCommanderJTF8', 'starfish-prime');
INSERT INTO films (id, operation_id, title, ia_identifier, ia_url, yield_kt, test_name, test_date, location, creator, downloads, description, aftermath, weapon, thumbnail_url, slug) VALUES ('atomic-explosion-five-bombs', NULL, 'Atomic Explosion: The Story Of Five Atomic Bombs', 'AtomicExplosionTheStoryOfFiveAtomicBombs', 'https://archive.org/details/AtomicExplosionTheStoryOfFiveAtomicBombs', NULL, 'Compilation', NULL, 'Various', 'Department of Energy', 9877, 'A Department of Energy compilation, ''The Story of Five Atomic Bombs,'' assembling footage of several detonations into a single documentary account of the weapons and their effects.', 'Like the other official compilations, it presents the explosions as technical achievements, the fireballs framed as data rather than as the leading edge of fallout that would settle, unannounced, over inhabited land.', 'Compilation', 'https://archive.org/services/img/AtomicExplosionTheStoryOfFiveAtomicBombs', 'atomic-explosion-five-bombs');
